#!/bin/bash\n\n# 🏗️ Bankikuw - Installation Script\n# منصة بناء المواقع الإلكترونية\n\necho \"🎉 مرحباً في Bankikuw!\"\necho \"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\"\necho \"\"\n\n# Check Node.js\necho \"✓ التحقق من Node.js...\"\nif ! command -v node &> /dev/null; then\n    echo \"❌ Node.js غير مثبت. يرجى تثبيت Node.js 16 أو أحدث\"\n    exit 1\nfi\necho \"✅ Node.js $(node -v) مثبت\"\necho \"\"\n\n# Install dependencies\necho \"📦 تثبيت المكتبات...\"\nnpm install\nif [ $? -ne 0 ]; then\n    echo \"❌ فشل تثبيت المكتبات\"\n    exit 1\nfi\necho \"✅ تم تثبيت المكتبات بنجاح\"\necho \"\"\n\n# Copy environment file\nif [ ! -f .env.local ]; then\n    echo \"⚙️ نسخ متغيرات البيئة...\"\n    cp .env.example .env.local\n    echo \"✅ تم إنشاء .env.local\"\nelse\n    echo \"✓ ملف .env.local موجود بالفعل\"\nfi\necho \"\"\n\n# Build project\necho \"🔨 بناء المشروع...\"\nnpm run build\nif [ $? -ne 0 ]; then\n    echo \"❌ فشل بناء المشروع\"\n    exit 1\nfi\necho \"✅ تم بناء المشروع بنجاح\"\necho \"\"\n\necho \"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\"\necho \"✅ تم التثبيت بنجاح!\"\necho \"\"\necho \"🚀 لتشغيل المشروع:\"\necho \"   npm run dev\"\necho \"\"\necho \"📖 للمزيد من المعلومات:\"\necho \"   اقرأ README.md\"\necho \"\"\necho \"💻 الموقع سيكون متاح على:\"\necho \"   http://localhost:3000\"\necho \"\"\n"